'use client';

import { useEffect, useState } from 'react';

interface ECF {
    id: string;
    eNcf: string;
    tipoEcf: number;
    fechaEmision: string;
    totalFacturado: number;
    estadoDgii: string;
    createdAt: string;
}

export default function InvoicesTable() {
    const [invoices, setInvoices] = useState<ECF[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const fetchInvoices = async () => {
        try {
            // Hardcoded tenant ID for Sprint 2 testing. Normally comes from context.
            const res = await fetch('http://localhost:3002/api/v1/ecf?tenantId=b0a8c2f1-9d3e-4f5a-8b1c-7e6d5f4a3b2c', {
                headers: { 'x-tenant-id': 'b0a8c2f1-9d3e-4f5a-8b1c-7e6d5f4a3b2c' }
            });
            if (!res.ok) throw new Error('Error al cargar comprobantes');
            const data = await res.json();
            setInvoices(data.data);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchInvoices();

        // Setup WebSocket for realtime status updates
        // Assuming ecf-service is running on 3002
        const ws = new WebSocket('ws://localhost:3002/api/v1/ecf/stream');

        ws.onmessage = (event) => {
            try {
                const message = JSON.parse(event.data);
                // Specifically look for e-CF status updates
                if (message.type === 'ECF_STATUS_UPDATE' && message.data) {
                    const { ecfId, estadoDgii } = message.data;
                    setInvoices((prev) =>
                        prev.map(inv => inv.id === ecfId ? { ...inv, estadoDgii } : inv)
                    );
                }
            } catch (e) {
                console.error("WS parse error", e);
            }
        };

        return () => {
            ws.close();
        };
    }, []);

    if (loading) return <div className="px-6 py-12 text-center text-gray-500">Cargando comprobantes...</div>;
    if (error) return <div className="px-6 py-12 text-center text-red-500 bg-red-50">{error}</div>;

    return (
        <ul role="list" className="divide-y divide-gray-200">
            {invoices.length === 0 ? (
                <li className="px-6 py-12 text-center text-gray-500">
                    No hay comprobantes emitidos.
                </li>
            ) : (
                invoices.map((invoice) => (
                    <li key={invoice.id} className="px-6 py-4 hover:bg-gray-50 transition">
                        <div className="flex items-center justify-between">
                            <div className="flex flex-col">
                                <p className="text-sm font-medium text-blue-600 truncate">
                                    {invoice.eNcf}
                                </p>
                                <div className="mt-2 flex">
                                    <div className="flex items-center text-sm text-gray-500">
                                        <span className="truncate">Monto: ${invoice.totalFacturado.toFixed(2)} DOP</span>
                                    </div>
                                </div>
                            </div>
                            <div className="flex flex-col items-end">
                                <div className="flex flex-col">
                                    {invoice.estadoDgii === 'PENDIENTE' && (
                                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
                                            Pendiente / En Cola
                                        </span>
                                    )}
                                    {invoice.estadoDgii === 'APROBADO' && (
                                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                                            Aceptado DGII
                                        </span>
                                    )}
                                    {invoice.estadoDgii === 'RECHAZADO' && (
                                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
                                            Rechazado
                                        </span>
                                    )}
                                </div>
                                <div className="mt-2 flex items-center text-xs text-gray-500">
                                    <time dateTime={invoice.fechaEmision}>
                                        {new Date(invoice.fechaEmision).toLocaleString('es-DO')}
                                    </time>
                                </div>
                            </div>
                        </div>
                    </li>
                ))
            )}
        </ul>
    );
}
